     2|import { getDb } from '@/lib/db'
     3|import crypto from 'crypto'
     4|
     5|// Simple in-memory rate limiter
     6|const loginAttempts = new Map<string, { count: number; blockUntil: number }>()
     7|
     8|function checkLoginRate(email: string, ip: string): { ok: boolean; error?: string } {
     9|  const key = email + ':' + ip
    10|  const now = Date.now()
    11|  const entry = loginAttempts.get(key)
    12|  if (entry && now < entry.blockUntil) {
    13|    return { ok: false, error: 'Demasiados intentos. Intente de nuevo en 5 minutos.' }
    14|  }
    15|  if (entry) {
    16|    entry.count++
    17|    if (entry.count >= 5) {
    18|      entry.blockUntil = now + 300000 // 5 min
    19|      return { ok: false, error: 'Demasiados intentos. Cuenta bloqueada por 5 minutos.' }
    20|    }
    21|  } else {
    22|    loginAttempts.set(key, { count: 1, blockUntil: 0 })
    23|  }
    24|  return { ok: true }
    25|}
    26|
    27|function hashPassword(p: string): string {
    28|  const salt = crypto.randomBytes(16).toString('hex')
    29|  return salt + ':' + crypto.pbkdf2Sync(p, salt, 10000, 64, 'sha512').toString('hex')
    30|}
    31|function verifyPassword(p: string, stored: string): boolean {
    32|  const [salt, hash] = stored.split(':')
    33|  return hash === crypto.pbkdf2Sync(p, salt, 10000, 64, 'sha512').toString('hex')
    34|}
    35|
    36|export async function POST(req: NextRequest) {
    37|  try {
    38|    const body = await req.json()
    39|    const db = getDb()
    40|    const { action } = body
    41|
    42|    if (action === 'login') {
    43|      const ip = req.headers.get('x-forwarded-for')?.split(',')[0]?.trim() || 'unknown'
    44|      const email = body.email || ''
    45|      const rateResult = checkLoginRate(email, ip)
    46|      if (!rateResult.ok) return NextResponse.json({ ok: false, error: rateResult.error }, { status: 429 })
    47|
    48|      const user: any = db.prepare('SELECT * FROM users WHERE email = ?').get(email)
    49|      if (!user || !verifyPassword(body.password || '', user.password)) {
    50|        return NextResponse.json({ ok: false, error: 'Credenciales incorrectas' }, { status: 401 })
    51|      }
    52|      const token = crypto.randomBytes(32).toString('hex')
    53|      db.prepare("INSERT INTO sessions (token, user_id, expires_at) VALUES (?, ?, datetime('now', '+7 days'))").run(token, user.id)
    54|      return NextResponse.json({ ok: true, token, user: { id: user.id, name: user.name, email: user.email, phone: user.phone, createdAt: user.created_at } })
    55|    }
    56|
    57|    if (action === 'register') {
    58|      const ip = req.headers.get('x-forwarded-for')?.split(',')[0]?.trim() || 'unknown'
    59|      const email = body.email || ''
    60|      const rateResult = checkLoginRate(email, ip)
    61|      if (!rateResult.ok) return NextResponse.json({ ok: false, error: rateResult.error }, { status: 429 })
    62|
    63|      const { name, email: mail, password, phone } = body
    64|      if (!name || !mail || !password || password.length < 6) {
    65|        return NextResponse.json({ ok: false, error: 'Datos invalidos' }, { status: 400 })
    66|      }
    67|      if (db.prepare('SELECT id FROM users WHERE email = ?').get(mail)) {
    68|        return NextResponse.json({ ok: false, error: 'Email ya registrado' }, { status: 409 })
    69|      }
    70|      const id = crypto.randomUUID()
    71|      db.prepare('INSERT INTO users (id, name, email, password, phone) VALUES (?, ?, ?, ?, ?)').run(id, name, mail, hashPassword(password), phone || '')
    72|      return NextResponse.json({ ok: true, user: { id, name, email: mail, phone: phone || '' } })
    73|    }
    74|
    75|    if (action === 'me') {
    76|      const session: any = db.prepare("SELECT u.id, u.name, u.email, u.phone, u.created_at FROM sessions s JOIN users u ON s.user_id = u.id WHERE s.token = ? AND s.expires_at > datetime('now')").get(body.token)
    77|      if (!session) return NextResponse.json({ ok: false, error: 'Sesion invalida' }, { status: 401 })
    78|      return NextResponse.json({ ok: true, user: session })
    79|    }
    80|
    81|    if (action === 'logout') {
    82|      db.prepare('DELETE FROM sessions WHERE token = ?').run(body.token)
    83|      return NextResponse.json({ ok: true })
    84|    }
    85|
    86|    return NextResponse.json({ error: 'Accion desconocida' }, { status: 400 })
    87|  } catch (err) {
    88|    return NextResponse.json({ error: String(err) }, { status: 500 })
    89|  }
